import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as d,a2 as s}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"WebDAV Site Access (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"my/Safety/webdav-site-access.md","filePath":"my/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),n={name:"my/Safety/webdav-site-access.md"};function o(r,e,c,p,h,g){return l(),d("div",null,[...e[0]||(e[0]=[s('<h1 id="webdav-site-access-beta" tabindex="-1">WebDAV Site Access (Beta) <a class="header-anchor" href="#webdav-site-access-beta" aria-label="Permalink to &quot;WebDAV Site Access (Beta)&quot;">​</a></h1><p>Security Settings ထဲက WebDAV setting က သင့် ImgBed site ကို WebDAV endpoint အဖြစ်ဖော်ထုတ်ပေးပါတယ်။</p><p>enable လုပ်ပြီးနောက် Windows, macOS, mobile file managers သို့မဟုတ် WebDAV-compatible client တစ်ခုခုနဲ့ ImgBed files တွေကို remote folder လို browse, upload, delete, manage လုပ်နိုင်ပါတယ်။</p><p>ဒါက site ရဲ့ WebDAV access entry ဖြစ်ပါတယ်။ Upload Settings ထဲက WebDAV storage channel နဲ့မတူပါ။ upload channel က third-party WebDAV service ထဲ files သိမ်းပါတယ်။ ဒီ setting က သင့် ImgBed site ကို clients အတွက် WebDAV access ပေးစေပါတယ်။</p><h2 id="ဘယ်နေရာမှာ-configure-လုပ်မလဲ" tabindex="-1">ဘယ်နေရာမှာ Configure လုပ်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-configure-လုပ်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ Configure လုပ်မလဲ&quot;">​</a></h2><p>admin panel ကိုဖွင့်ပြီး သွားပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Available settings:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="ဒီ-feature-က-ဘာလုပ်လဲ" tabindex="-1">ဒီ Feature က ဘာလုပ်လဲ <a class="header-anchor" href="#ဒီ-feature-က-ဘာလုပ်လဲ" aria-label="Permalink to &quot;ဒီ Feature က ဘာလုပ်လဲ&quot;">​</a></h2><p>WebDAV enabled ဖြစ်ပြီးနောက် ImgBed က fixed access URL တစ်ခုပေးပါတယ်:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>ImgBed file directory ကို connect လုပ်ဖို့ ဒီ URL ကိုသုံးပါ။</p><p>သင့်တော်တဲ့ use cases:</p><ul><li>computer file manager မှ ImgBed files ကိုတိုက်ရိုက် browse လုပ်ရန်။</li><li>images တွေကို WebDAV folder ထဲ drag လုပ်ပြီး upload လုပ်ရန်။</li><li>local file manager နဲ့ ImgBed folders ကို organize လုပ်ရန်။</li><li>WebDAV-compatible software နဲ့ images sync/manage လုပ်ရန်။</li><li>admin panel မဖွင့်ဘဲ ImgBed content access လုပ်ရန်။</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>WebDAV endpoint ကို on လုပ်ပါတယ်။</p><p>disabled ဖြစ်လျှင် clients တွေက WebDAV မှတစ်ဆင့် connect မလုပ်နိုင်ပါ။</p><h3 id="username-နှင့်-password" tabindex="-1">Username နှင့် Password <a class="header-anchor" href="#username-နှင့်-password" aria-label="Permalink to &quot;Username နှင့် Password&quot;">​</a></h3><p>WebDAV clients တွေ connect လုပ်တဲ့အခါ ဒီ credentials တွေကိုသုံးပါတယ်။</p><p>dedicated WebDAV username နဲ့ password သုံးပါ။ admin password သို့မဟုတ် upload password ကိုပြန်မသုံးပါနှင့်။</p><p>username သို့မဟုတ် password တစ်ခုခုဗလာဖြစ်လျှင် WebDAV clients တွေက မှန်မှန်ကန်ကန် connect မလုပ်နိုင်ပါ။</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode က WebDAV clients တွေ images ဖတ်တဲ့အခါ ဘယ် image URL ကိုဦးစားပေးသုံးမလဲ ဆုံးဖြတ်ပါတယ်။</p><p>Common choices:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed က context အပေါ်မူတည်ပြီးရွေးသည်။ normal use အတွက် recommended။</td></tr><tr><td>Original</td><td>original images ကိုဦးစားပေးသည်။</td></tr><tr><td>Thumbnail</td><td>thumbnails ကိုဦးစားပေးသည်။ fast preview အတွက်အသုံးဝင်သည်။</td></tr></tbody></table><p>မသေချာလျှင် <code>Smart loading</code> ကိုထားပါ။</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>default channel ကို WebDAV uploads အတွက်သုံးပါတယ်။</p><p>Windows သို့မဟုတ် အခြား client မှ WebDAV directory ထဲ files copy လုပ်တဲ့အခါ ImgBed က selected default upload channel မှတစ်ဆင့် upload လုပ်ပါတယ်။</p><p>default channel မရွေးထားလျှင် browsing ကအလုပ်လုပ်နိုင်ပေမယ့် uploads fail ဖြစ်နိုင်ပါတယ်။</p><h2 id="windows-11-မှာ-webdav-access-လုပ်ခြင်း" tabindex="-1">Windows 11 မှာ WebDAV Access လုပ်ခြင်း <a class="header-anchor" href="#windows-11-မှာ-webdav-access-လုပ်ခြင်း" aria-label="Permalink to &quot;Windows 11 မှာ WebDAV Access လုပ်ခြင်း&quot;">​</a></h2><p>Windows 11 မှာ WebDAV ကို network location အဖြစ် add လုပ်နိုင်ပါတယ်။</p><ol><li><code>This PC</code> ကိုဖွင့်ပါ။</li><li><code>Add a network location</code> ကိုရွေးပါ။</li><li><code>https://your-domain.com/dav</code> ထည့်ပါ။</li><li>prompt ပြလာရင် WebDAV username နဲ့ password ထည့်ပါ။</li><li>wizard ကိုပြီးအောင်လုပ်ပါ။ ပြီးရင် WebDAV directory ကို File Explorer မှာဖွင့်နိုင်ပါမယ်။</li></ol><p><img src="'+a+'" alt="Add WebDAV in Windows 11" loading="lazy"></p><p>add လုပ်ပြီးနောက် WebDAV directory က Windows File Explorer မှာပေါ်လာပါမယ်။ normal folder လို files တွေကို open, copy, manage လုပ်နိုင်ပါတယ်။</p><p><img src="'+t+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>WebDAV connection အောင်မြင်ပြီးနောက် များသောအားဖြင့်:</p><ul><li>files နဲ့ folders တွေကြည့်နိုင်သည်။</li><li>files upload လုပ်နိုင်သည်။</li><li>folders ဖန်တီးနိုင်သည်။</li><li>files သို့မဟုတ် folders rename လုပ်နိုင်သည်။</li><li>files move လုပ်နိုင်သည်။</li><li>files delete လုပ်နိုင်သည်။</li></ul><p>WebDAV က everyday access နဲ့ small-scale file management အတွက်ကောင်းပါတယ်။ large moves, bulk deletes, complex organization အတွက် admin panel ကိုသုံးပါ။</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>အောင်မြင်တဲ့ WebDAV connections တွေက Login Device Management ထဲက WebDAV tab မှာလည်းပေါ်ပါတယ်။</p><p>အဲဒီမှာ WebDAV clients တွေကို review လုပ်ပြီးလိုအပ်လျှင် old devices တွေကို force offline လုပ်နိုင်ပါတယ်။</p><p>WebDAV username သို့မဟုတ် password ပြောင်းလဲလျှင် old clients တွေက ပြန် sign in ဝင်ရပါမယ်။</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-က-username-နဲ့-password-ကိုထပ်ခါထပ်ခါတောင်းနေတယ်" tabindex="-1">Windows က Username နဲ့ Password ကိုထပ်ခါထပ်ခါတောင်းနေတယ် <a class="header-anchor" href="#windows-က-username-နဲ့-password-ကိုထပ်ခါထပ်ခါတောင်းနေတယ်" aria-label="Permalink to &quot;Windows က Username နဲ့ Password ကိုထပ်ခါထပ်ခါတောင်းနေတယ်&quot;">​</a></h3><p>စစ်ပါ:</p><ul><li>URL က <code>https://your-domain.com/dav</code> ဖြစ်လား။</li><li>username နဲ့ password က WebDAV settings နဲ့ကိုက်လား။</li><li>WebDAV enabled ဖြစ်လား။</li><li>site ကို HTTPS မှတစ်ဆင့် access လုပ်လို့ရလား။</li></ul><h3 id="browsing-အလုပ်လုပ်ပေမယ့်-uploading-fail-ဖြစ်တယ်" tabindex="-1">Browsing အလုပ်လုပ်ပေမယ့် Uploading fail ဖြစ်တယ် <a class="header-anchor" href="#browsing-အလုပ်လုပ်ပေမယ့်-uploading-fail-ဖြစ်တယ်" aria-label="Permalink to &quot;Browsing အလုပ်လုပ်ပေမယ့် Uploading fail ဖြစ်တယ်&quot;">​</a></h3><p><code>Default channel</code> ကိုစစ်ပါ။</p><p>WebDAV uploads အတွက် default upload channel လိုပါတယ်။ မရှိ၊ disabled ဖြစ်၊ misconfigured ဖြစ်လျှင် uploads fail ဖြစ်နိုင်ပါတယ်။</p><h3 id="access-speed-မတည်ငြိမ်ဘူး" tabindex="-1">Access Speed မတည်ငြိမ်ဘူး <a class="header-anchor" href="#access-speed-မတည်ငြိမ်ဘူး" aria-label="Permalink to &quot;Access Speed မတည်ငြိမ်ဘူး&quot;">​</a></h3><p>WebDAV performance က client, network, file count, default upload channel အပေါ်မူတည်ပါတယ်။</p><p>directory တစ်ခုထဲမှာ files အရမ်းများနေလျှင် folders တွေထဲ organize လုပ်ပါ။</p><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><ul><li>WebDAV access အတွက် HTTPS သုံးပါ။</li><li>strong password သတ်မှတ်ပါ။</li><li>WebDAV password ကိုမယုံကြည်ရသူတွေနဲ့မမျှဝေပါနှင့်။</li><li>မသုံးတဲ့အခါ WebDAV ကို off လုပ်ပါ။</li><li>Login Device Management ထဲမှာ unused WebDAV devices တွေကိုအချိန်ပိုင်းလိုက် clean up လုပ်ပါ။</li></ul><h2 id="webdav-upload-file-size" tabindex="-1">WebDAV Upload File Size <a class="header-anchor" href="#webdav-upload-file-size" aria-label="Permalink to &quot;WebDAV Upload File Size&quot;">​</a></h2><p>WebDAV clients တွေက browser upload page ရဲ့ large-file chunking flow ကိုမသုံးပါ။ အောက်က suggested limits ထက်ကြီးတဲ့ files အတွက် web upload page ကိုသုံးပါ။</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Suggested Single-File Limit for WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const f=i(n,[["render",o]]);export{u as __pageData,f as default};
